#include <sys/socket.h>
#include <arpa/inet.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/stat.h>
#include <sys/types.h>
#include <errno.h>

int main(void)
{
    int sock;
    struct sockaddr_in server;
    char message[1024], server_reply[1024];
    int fd;
    char *fifo = "/dev/log/main"; // 指定读取的日志文件
    int len;

    // 创建socket
    sock = socket(AF_INET, SOCK_STREAM, 0);
    if (sock == -1) {
        printf("Could not create socket");
        exit(EXIT_FAILURE);
    }

    // 初始化server
    server.sin_addr.s_addr = inet_addr("127.0.0.1"); // 服务器IP地址，此处为本地IP
    server.sin_family = AF_INET;
    server.sin_port = htons(8888);  // 服务器端口

    // 连接服务器
    if (connect(sock, (struct sockaddr *)&server, sizeof(server)) < 0) {
        perror("Connect failed. Error");
        return 1;
    }

    // 打开日志文件
    fd = open(fifo, O_RDONLY);
    if (fd < 0) {
        perror("open");
        exit(EXIT_FAILURE);
    }

    // 循环读取日志文件并发送给服务器
    while (1) {
        len = read(fd, message, sizeof(message));
        if (len > 0) {
            printf("%s", message); // 在本地输出日志信息
            if (send(sock, message, len, 0) < 0) {
                perror("Send failed");
                return 1;
            }
        }
        else if (len < 0) {
            if (errno == EINTR) {
                continue;
            }
            perror("read");
            exit(EXIT_FAILURE);
        }
        else if (len == 0) {
            printf("The end of file\n");
        }
    }

    close(sock);
    return 0;
}
```

